const item = $input.first();
let html = '';
if (typeof item.json === 'string') {
  html = item.json;
} else if (typeof item.json.data === 'string') {
  html = item.json.data;
} else if (typeof item.json.body === 'string') {
  html = item.json.body;
} else {
  html = JSON.stringify(item.json);
}

if (!html || html.length < 50) {
  return [{ json: { error: '抓取失敗：找不到網頁內容' } }];
}

function stripTags(s) {
  return s
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\s+/g, ' ')
    .trim();
}

let cleaned = html
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<nav[\s\S]*?<\/nav>/gi, ' ')
  .replace(/<footer[\s\S]*?<\/footer>/gi, ' ')
  .replace(/<header[\s\S]*?<\/header>/gi, ' ')
  .replace(/<!--[\s\S]*?-->/g, ' ');

const articleMatch = cleaned.match(/<article[^>]*>([\s\S]*?)<\/article>/i);

let text = '';
if (articleMatch) {
  text = stripTags(articleMatch[1]);
} else {
  const paragraphs = [...cleaned.matchAll(/<p[^>]*>([\s\S]*?)<\/p>/gi)].map((m) => stripTags(m[1]));
  text = paragraphs.filter((p) => p.length > 40).join('\n\n');
  if (!text) {
    text = stripTags(cleaned);
  }
}

const titleMatch = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
const title = titleMatch ? stripTags(titleMatch[1]) : '';

if (!text || text.length < 200) {
  return [{ json: { error: `抓取內容過短或找不到主要內文（${text.length} 字）` } }];
}

return [{ json: { title, text, chars: text.length } }];
